<script setup lang="ts">
import{Head,Link,usePage}from'@inertiajs/vue3';import{AlertCircle,ArrowLeft,CheckCircle2,Plus,Send,Trash2}from'@lucide/vue';import{computed,onMounted,ref}from'vue';import AppShell from '../../Layouts/AppShell.vue';
const user=(usePage().props.auth as any)?.user,roles=user?.roles?.map((r:any)=>typeof r==='string'?r:r.name)??[];const allowed=computed(()=>roles.some((r:string)=>['club','academy','business','sponsor','admin'].includes(r)));const sports=ref<any[]>([]),saving=ref(false),notice=ref(''),error=ref('');const documentTypes=[['CV / résumé','resumes'],['Certificate','certificates'],['Identity document','identity'],['Medical document','medical'],['Portfolio / highlights','gallery'],['Other document','uploads']];const form=ref<any>({title:'',type:'trial',description:'',sport_id:'',position_id:'',country:'ZA',province:'',city:'',is_remote:false,minimum_age:'',maximum_age:'',deadline:'',requirements:[''],required_documents:[],publish:true});const positions=computed(()=>sports.value.find(s=>String(s.id)===form.value.sport_id)?.positions??[]),csrf=()=>document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content??'';const add=()=>form.value.requirements.push(''),remove=(i:number)=>form.value.requirements.splice(i,1);const addDocument=()=>form.value.required_documents.push({key:`document_${Date.now()}`,label:'CV / résumé',collection:'resumes',required:true});const removeDocument=(i:number)=>form.value.required_documents.splice(i,1);const setDocumentType=(document:any,value:string)=>{const option=documentTypes.find(type=>type[1]===value);document.collection=value;document.label=option?.[0]??'Document'};const submit=async()=>{saving.value=true;error.value='';notice.value='';try{const r=await fetch('/api/v1/opportunities',{method:'POST',credentials:'same-origin',headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf()},body:JSON.stringify({...form.value,sport_id:+form.value.sport_id||null,position_id:+form.value.position_id||null,minimum_age:+form.value.minimum_age||null,maximum_age:+form.value.maximum_age||null,deadline:form.value.deadline||null,requirements:form.value.requirements.filter(Boolean)})}),p=await r.json();if(!r.ok)throw new Error(p.message??Object.values(p.errors??{}).flat().join(' '));notice.value=form.value.publish?'Opportunity published successfully.':'Draft saved successfully.'}catch(e:any){error.value=e.message}finally{saving.value=false}};onMounted(async()=>{const r=await fetch('/api/v1/sports',{headers:{Accept:'application/json'}});sports.value=(await r.json()).data??[]});
</script>
<template><Head title="Post Opportunity"/><AppShell><main class="create-opportunity"><header><Link href="/opportunities"><ArrowLeft/>Back to opportunities</Link><h1>Post an opportunity</h1><p>Create a trial, camp, job, scout day or sponsorship listing.</p></header><section v-if="!allowed" class="opp-denied"><AlertCircle/><h2>Posting is not available for this role</h2><p>Fans and athletes can discover, save and apply for opportunities, but cannot publish them. Opportunity posting is available to clubs, academies, businesses, sponsors and administrators.</p><Link href="/opportunities">Browse opportunities</Link></section><form v-else @submit.prevent="submit"><section><h2>Opportunity details</h2><div class="create-opp-fields"><label class="wide">Title<input v-model="form.title" required placeholder="e.g. U18 Football Talent Trial"/></label><label>Type<select v-model="form.type"><option v-for="v in ['trial','job','training_camp','sponsorship','scout_day','academy_application']" :key="v" :value="v">{{v.replaceAll('_',' ')}}</option></select></label><label>Deadline<input v-model="form.deadline" type="datetime-local" required/></label><label class="wide">Description<textarea v-model="form.description" required maxlength="20000" placeholder="Describe the opportunity, programme and ideal candidate..."/></label></div></section><section><h2>Sport and eligibility</h2><div class="create-opp-fields"><label>Sport<select v-model="form.sport_id"><option value="">All sports</option><option v-for="s in sports" :key="s.id" :value="String(s.id)">{{s.name}}</option></select></label><label>Position<select v-model="form.position_id"><option value="">All positions</option><option v-for="p in positions" :key="p.id" :value="String(p.id)">{{p.name}}</option></select></label><label>Minimum age<input v-model="form.minimum_age" type="number" min="5" max="100"/></label><label>Maximum age<input v-model="form.maximum_age" type="number" min="5" max="100"/></label></div></section><section><h2>Location</h2><div class="create-opp-fields"><label>Country code<input v-model="form.country" maxlength="2"/></label><label>Province<input v-model="form.province"/></label><label>City / town<input v-model="form.city"/></label><label class="check-field"><input v-model="form.is_remote" type="checkbox"/>Remote opportunity</label></div></section><section><header class="requirements-head"><h2>Candidate requirements</h2><button type="button" @click="add"><Plus/>Add requirement</button></header><div class="requirements-list"><label v-for="(_,i) in form.requirements" :key="i"><input v-model="form.requirements[i]" :placeholder="`Requirement ${i+1}`"/><button v-if="form.requirements.length>1" type="button" @click="remove(i)"><Trash2/></button></label></div></section><section><header class="requirements-head"><div><h2>Documents to submit</h2><p>Applicants can select these directly from their SportUniverse Library.</p></div><button type="button" @click="addDocument"><Plus/>Add document</button></header><div v-if="form.required_documents.length" class="opportunity-document-builder"><div v-for="(document,i) in form.required_documents" :key="document.key"><label>Document type<select :value="document.collection" @change="setDocumentType(document,($event.target as HTMLSelectElement).value)"><option v-for="option in documentTypes" :value="option[1]">{{option[0]}}</option></select></label><label>Label shown to applicant<input v-model="document.label" required/></label><label class="check-field"><input v-model="document.required" type="checkbox"/>Required</label><button type="button" aria-label="Remove document" @click="removeDocument(i)"><Trash2/></button></div></div><p v-else class="document-builder-empty">No documents requested. Applicants will only provide their message.</p></section><p v-if="error" class="edit-message error">{{error}}</p><p v-if="notice" class="edit-message success"><CheckCircle2/>{{notice}}</p><footer><label><input v-model="form.publish" type="checkbox"/>Publish immediately</label><div><Link href="/opportunities">Cancel</Link><button :disabled="saving"><Send/>{{saving?'Saving…':form.publish?'Publish opportunity':'Save draft'}}</button></div></footer></form></main></AppShell></template>

<style scoped>.requirements-head>div p{margin:.2rem 0 0;color:#718096;font-size:.72rem}.opportunity-document-builder{display:grid;gap:.7rem}.opportunity-document-builder>div{display:grid;grid-template-columns:1fr 1.3fr auto auto;gap:.7rem;align-items:end;padding:.8rem;border:1px solid #e1e7ef;border-radius:12px;background:#f8fafc}.opportunity-document-builder label{display:grid;gap:.35rem;font-size:.7rem;font-weight:750}.opportunity-document-builder .check-field{display:flex;align-items:center;padding-bottom:.75rem}.opportunity-document-builder>div>button{width:38px;height:38px;color:#d92c5c;border:1px solid #f0cbd6;border-radius:9px;background:#fff}.document-builder-empty{padding:1rem;color:#718096;border-radius:10px;background:#f5f7fa;font-size:.72rem}@media(max-width:700px){.opportunity-document-builder>div{grid-template-columns:1fr}.opportunity-document-builder .check-field{padding:0}}</style>
